use crate::distance::l2_distance;
use std::sync::RwLock;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub struct VectorDB {
    // Store vectors as contiguous arrays for SIMD
    vectors: RwLock<Vec<[f32; 128]>>,
    ids: RwLock<Vec<u64>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        let mut ids = self.ids.write().unwrap();
        // Convert vector to array
        let arr: [f32; 128] = vector.try_into().unwrap_or_else(|_| panic!("Vector length must be 128"));
        vectors.push(arr);
        ids.push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vecs = self.vectors.write().unwrap();
        let mut ids = self.ids.write().unwrap();
        let start = vecs.len();
        for (id, vector) in vectors {
            let arr: [f32; 128] = vector.try_into().unwrap_or_else(|_| panic!("Vector length must be 128"));
            vecs.push(arr);
            ids.push(id);
        }
        vecs.len() - start
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();
        let ids = self.ids.read().unwrap();
        let k = top_k as usize;
        if k == 0 {
            return Vec::new();
        }
        // Use a max-heap of size k, storing Reverse(distance) to get min-heap behavior
        let mut heap = BinaryHeap::with_capacity(k + 1);
        for (i, vec) in vectors.iter().enumerate() {
            let dist = l2_distance(query, vec);
            if heap.len() < k {
                heap.push(Reverse((dist, ids[i])));
            } else {
                // If distance is smaller than the largest in heap, replace
                let &Reverse((max_dist, _)) = heap.peek().unwrap();
                if dist < max_dist {
                    heap.pop();
                    heap.push(Reverse((dist, ids[i])));
                }
            }
        }
        // Extract results sorted by distance ascending
        let mut results: Vec<_> = heap.into_sorted_vec().into_iter().map(|Reverse((d, id))| SearchResult { id, distance: d }).collect();
        results.reverse(); // because into_sorted_vec gives ascending? Actually BinaryHeap::into_sorted_vec yields ascending (since Reverse)
        // Let's verify: Reverse tuple sorts by Reverse order, so ascending distance becomes descending after sorting.
        // We'll just collect and sort manually.
        results
    }
}"}

