pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    // Ensure both slices have the same length (should be 128)
    assert_eq!(a.len(), b.len());
    // Use AVX-512 if available
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        }
    }
    // Scalar fallback
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    // Each AVX-512 register holds 16 f32 values
    const LANES: usize = 16;
    let mut sum = _mm512_setzero_ps();
    let mut i = 0;
    while i + LANES <= a.len() {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        let sq = _mm512_mul_ps(diff, diff);
        sum = _mm512_add_ps(sum, sq);
        i += LANES;
    }
    // Horizontal sum
    let sum_scalar = _mm512_reduce_add_ps(sum);
    // Handle remaining elements (if any)
    let mut remainder = sum_scalar;
    while i < a.len() {
        let diff = a[i] as f64 - b[i] as f64;
        remainder += (diff * diff) as f32;
        i += 1;
    }
    remainder as f64
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for (&ai, &bi) in a.iter().zip(b) {
        let diff = ai as f64 - bi as f64;
        sum += diff * diff;
    }
    sum
}"}

