        i += LANES;
    }
    // Horizontal sum
    let sum_scalar = _mm512_reduce_add_ps(sum);
    // Handle remaining elements (if any) - should be none for 128 dimensions
    let mut remainder = sum_scalar as f64;
    while i < len {
        let diff = a[i] as f64 - b[i] as f64;
        remainder += diff * diff;
        i += 1;
    }
    remainder
}

