    let mut sum = 0.0f64;
    for (&ai, &bi) in a.iter().zip(b) {
        let diff = ai as f64 - bi as f64;
        sum += diff * diff;
    }
    sum
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_l2_distance() {
        let a = [1.0f32; 128];
        let b = [2.0f32; 128];
        let scalar = l2_distance_scalar(&a, &b);
