use crate::distance::l2_distance;
use std::sync::RwLock;
use std::collections::BinaryHeap;
use std::cmp::Ordering;
use rayon::prelude::*;

// Wrapper for distance to allow ordering
#[derive(Debug, Clone, Copy)]
struct DistanceKey {
    distance: f64,
    id: u64,
}

impl PartialEq for DistanceKey {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance && self.id == other.id
    }
}

impl Eq for DistanceKey {}

impl PartialOrd for DistanceKey {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Compare by distance descending, then by id ascending for tie-breaking
        if self.distance > other.distance {
            Some(Ordering::Greater)
        } else if self.distance < other.distance {
            Some(Ordering::Less)
        } else {
            // Distances equal, compare ids
            self.id.partial_cmp(&other.id)
        }
    }
}

impl Ord for DistanceKey {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

pub struct VectorDB {
    // Store vectors and ids together for better locality
    data: RwLock<Vec<([f32; 128], u64)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        let arr: [f32; 128] = vector.try_into().unwrap_or_else(|_| panic!("Vector length must be 128"));
        data.push((arr, id));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let start = data.len();
        for (idx, (id, vector)) in vectors.into_iter().enumerate() {
            if idx == 0 {
                eprintln!("First vector length: {}", vector.len());
            }
            let arr: [f32; 128] = vector.try_into().unwrap_or_else(|_| panic!("Vector length must be 128"));
            data.push((arr, id));
        }
        data.len() - start
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;
        if k == 0 {
            return Vec::new();
        }
        // Use parallel iterator
        let query = query.to_vec(); // clone for each thread
        let heap = data.par_iter()
            .fold(
                || BinaryHeap::with_capacity(k),
                |mut heap, (vec, id)| {
                    let dist = l2_distance(&query, vec);
                    let key = DistanceKey { distance: dist, id: *id };
                    if heap.len() < k {
                        heap.push(key);
                    } else {
                        let &max_key = heap.peek().unwrap();
                        if dist < max_key.distance {
                            heap.pop();
                            heap.push(key);
                        }
                    }
                    heap
                })
            .reduce(
                || BinaryHeap::with_capacity(k),
                |mut heap1, mut heap2| {
                    // Merge two heaps: push all elements from heap2 into heap1, maintaining size k
                    for key in heap2.into_iter() {
                        if heap1.len() < k {
                            heap1.push(key);
                        } else {
                            let &max_key = heap1.peek().unwrap();
                            if key.distance < max_key.distance {
                                heap1.pop();
                                heap1.push(key);
                            }
                        }
                    }
                    heap1
                });
        // Convert to sorted results
        let mut results: Vec<_> = heap.into_sorted_vec()
            .into_iter()
            .map(|key| SearchResult { id: key.id, distance: key.distance })
            .collect();
        // Ensure ascending order by distance
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}"}

